import { useTranslation } from 'react-i18next';
import { SUPPORTED_LANGUAGES } from '../i18n';

/**
 * Top-right language switch. Changing the language updates all UI text and triggers a
 * re-conversion of the current amount (handled in App via the i18n language).
 */
export function LanguageSwitch() {
  const { i18n, t } = useTranslation();
  const current = i18n.resolvedLanguage;

  return (
    <div className="language-switch" role="group" aria-label={t('languageLabel')}>
      {SUPPORTED_LANGUAGES.map((lng) => (
        <button
          key={lng}
          type="button"
          className={lng === current ? 'lang-button active' : 'lang-button'}
          aria-pressed={lng === current}
          onClick={() => i18n.changeLanguage(lng)}
        >
          {lng.toUpperCase()}
        </button>
      ))}
    </div>
  );
}

